#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI N=1e6+10;
int n,a[N],v[N],pre[N],lst[N];
ll dp[N],c[N];
void fix(int x,ll val)
{
    for(int i=x;i<=2*n;i+=lowbit(i)) c[i]=max(c[i],val);
}
ll get_max(int x)
{
    ll res=0;
    for(int i=x;i>0;i-=lowbit(i)) res=max(res,c[i]);
    return res;
}
signed main(void)
{
    n=read();
    FOR(i,1,2*n) a[i]=read();
    FOR(i,1,n) v[i]=read();
    FOR(i,1,2*n)
    {
        pre[i]=lst[a[i]];
        lst[a[i]]=i;
    }
    FOR(i,1,2*n)
    {
        dp[i]=dp[i-1];
        if(pre[i])
        {
            dp[i]=max(dp[i],dp[pre[i]]+v[a[i]]);
            dp[i]=max(dp[i],get_max(pre[i]-1)+v[a[i]]);
            fix(pre[i],dp[pre[i]]+v[a[i]]);
        }
    }
    writeln(dp[2*n]);
    return false;
}
